module.exports = function(options) {
  var bases, corepath;
  corepath = require('path');
  return bases = {
    global: function() {
      return ['/usr/lib/node_modules/', '/usr/local/lib/node_modules/'];
    },
    system: function() {
      return ['/etc/', '/etc/nuc/'];
    },
    user: function() {
      return [process.env.HOME + '/.conf/', process.env.HOME + '/conf/', process.env.HOME + '/'];
    },
    local: function() {
      var array, path;
      array = [];
      path = process.cwd();
      array.push(path + '/');
      while (path !== corepath.sep) {
        path = corepath.dirname(path);
        if (path.length !== 1) {
          path += '/';
        }
        array.unshift(path);
      }
      return array;
    }
  };
};
